    79→// cancelFunc updates unsynced and synced maps when running
    80→// cancel operations.
    81→type cancelFunc func()
    82→
    83→func New(lg *zap.Logger, b backend.Backend, le lease.Lessor, cfg StoreConfig) WatchableKV {
    84→	s := newWatchableStore(lg, b, le, cfg)
    85→	s.wg.Add(2)
    86→	go s.syncWatchersLoop()
    87→	go s.syncVictimsLoop()
    88→	return s
    89→}
    90→
    91→func newWatchableStore(lg *zap.Logger, b backend.Backend, le lease.Lessor, cfg StoreConfig) *watchableStore {
    92→	if lg == nil {
    93→		lg = zap.NewNop()
    94→	}
    95→	s := &watchableStore{
    96→		store:    NewStore(lg, b, le, cfg),
    97→		victimc:  make(chan struct{}, 1),
    98→		unsynced: newWatcherGroup(),
    99→		synced:   newWatcherGroup(),
   100→		stopc:    make(chan struct{}),
   101→	}
   102→	s.store.ReadView = &readView{s}
   103→	s.store.WriteView = &writeView{s}
   104→	if s.le != nil {
   105→		// use this store as the deleter so revokes trigger watch events
   106→		s.le.SetRangeDeleter(func() lease.TxnDelete { return s.Write(traceutil.TODO()) })
   107→	}
   108→	return s
   109→}
   110→
   111→func (s *watchableStore) Close() error {
   112→	close(s.stopc)
   113→	s.wg.Wait()
   114→	return s.store.Close()
   115→}
