   490→// notify notifies the fact that given event at the given rev just happened to
   491→// watchers that watch on the key of the event.
   492→func (s *watchableStore) notify(rev int64, evs []mvccpb.Event) {
   493→	victim := make(watcherBatch)
   494→	for w, eb := range newWatcherBatch(&s.synced, evs) {
   495→		if eb.revs != 1 {
   496→			s.store.lg.Panic(
   497→				"unexpected multiple revisions in watch notification",
   498→				zap.Int("number-of-revisions", eb.revs),
   499→			)
   500→		}
   501→		if w.send(WatchResponse{WatchID: w.id, Events: eb.evs, Revision: rev}) {
   502→			pendingEventsGauge.Add(float64(len(eb.evs)))
   503→		} else {
   504→			// move slow watcher to victims
   505→			w.victim = true
   506→			victim[w] = eb
   507→			s.synced.delete(w)
   508→			slowWatcherGauge.Inc()
   509→		}
   510→		// always update minRev
   511→		// in case 'send' returns true and watcher stays synced, this is needed for Restore when all watchers become unsynced
   512→		// in case 'send' returns false, this is needed for syncWatchers
   513→		w.minRev = rev + 1
   514→	}
   515→	s.addVictim(victim)
   516→}
   517→
   518→func (s *watchableStore) addVictim(victim watcherBatch) {
   519→	if len(victim) == 0 {
   520→		return
   521→	}
   522→	s.victims = append(s.victims, victim)
   523→	select {
   524→	case s.victimc <- struct{}{}:
   525→	default:
   526→	}
   527→}
   528→
   529→func (s *watchableStore) rev() int64 { return s.store.Rev() }
   530→
   531→func (s *watchableStore) progress(w *watcher) {
   532→	s.progressIfSync(map[WatchID]*watcher{w.id: w}, w.id)
   533→}
   534→
   535→func (s *watchableStore) progressAll(watchers map[WatchID]*watcher) bool {
   536→	return s.progressIfSync(watchers, clientv3.InvalidWatchID)
   537→}
   538→
   539→func (s *watchableStore) progressIfSync(watchers map[WatchID]*watcher, responseWatchID WatchID) bool {
   540→	s.mu.RLock()
   541→	defer s.mu.RUnlock()
   542→
   543→	rev := s.rev()
   544→	// Any watcher unsynced?
   545→	for _, w := range watchers {
   546→		if _, ok := s.synced.watchers[w]; !ok {
   547→			return false
   548→		}
   549→		if rev < w.startRev {
   550→			return false
   551→		}
   552→	}
   553→
   554→	// If all watchers are synchronised, send out progress
   555→	// notification on first watcher. Note that all watchers
   556→	// should have the same underlying stream, and the progress
   557→	// notification will be broadcasted client-side if required
   558→	// (see dispatchEvent in client/v3/watch.go)
   559→	for _, w := range watchers {
   560→		w.send(WatchResponse{WatchID: responseWatchID, Revision: rev})
   561→		return true
   562→	}
   563→	return true
   564→}
   565→
   566→type watcher struct {
   567→	// the watcher key
   568→	key []byte
   569→	// end indicates the end of the range to watch.
   570→	// If end is set, the watcher is on a range.
   571→	end []byte
   572→
   573→	// victim is set when ch is blocked and undergoing victim processing
   574→	victim bool
   575→
   576→	// compacted is set when the watcher is removed because of compaction
   577→	compacted bool
   578→
   579→	// restore is true when the watcher is being restored from leader snapshot
   580→	// which means that this watcher has just been moved from "synced" to "unsynced"
   581→	// watcher group, possibly with a future revision when it was first added
   582→	// to the synced watcher
   583→	// "unsynced" watcher revision must always be <= current revision,
   584→	// except when the watcher were to be moved from "synced" watcher group
   585→	restore bool
   586→
   587→	startRev int64
   588→	// minRev is the minimum revision update the watcher will accept
   589→	minRev int64
   590→	id     WatchID
   591→
   592→	fcs []FilterFunc
   593→	// a chan to send out the watch response.
   594→	// The chan might be shared with other watchers.
   595→	ch chan<- WatchResponse
   596→}
   597→
   598→func (w *watcher) send(wr WatchResponse) bool {
   599→	progressEvent := len(wr.Events) == 0
   600→
   601→	if len(w.fcs) != 0 {
   602→		ne := make([]mvccpb.Event, 0, len(wr.Events))
   603→		for i := range wr.Events {
   604→			filtered := false
   605→			for _, filter := range w.fcs {
   606→				if filter(wr.Events[i]) {
   607→					filtered = true
   608→					break
   609→				}
   610→			}
   611→			if !filtered {
   612→				ne = append(ne, wr.Events[i])
   613→			}
   614→		}
   615→		wr.Events = ne
   616→	}
   617→
   618→	verify.Verify("Event.ModRevision is less than the w.startRev for watchID", func() (bool, map[string]any) {
   619→		if w.startRev > 0 {
   620→			for _, ev := range wr.Events {
   621→				if ev.Kv.ModRevision < w.startRev {
   622→					return false, map[string]any{
   623→						"Event.ModRevision": ev.Kv.ModRevision,
   624→						"w.startRev":        w.startRev,
   625→						"watchID":           w.id,
   626→					}
   627→				}
   628→			}
   629→		}
   630→		return true, nil
   631→	})
   632→
   633→	// if all events are filtered out, we should send nothing.
   634→	if !progressEvent && len(wr.Events) == 0 {
   635→		return true
   636→	}
   637→	select {
   638→	case w.ch <- wr:
   639→		return true
   640→	default:
   641→		return false
   642→	}
   643→}
